from googletrans import Translator
from http.server import BaseHTTPRequestHandler, HTTPServer
from urllib.parse import urlparse, parse_qs, unquote, quote
import json
import os

text_decode_cache = {}
translate_cache = {}

def url_decode(encoded_str):
    """
    Decodes a URL-encoded string (percent-encoding).
    Handles UTF-8 characters correctly.
    """
    if not isinstance(encoded_str, str):
        raise TypeError("Input must be a string.")
    
    # Decode percent-encoded characters
    decoded_str = unquote(encoded_str)
    return decoded_str
    
def url_encode(encoded_str):
    """
    Decodes a URL-encoded string (percent-encoding).
    Handles UTF-8 characters correctly.
    """
    if not isinstance(encoded_str, str):
        raise TypeError("Input must be a string.")
    
    # Decode percent-encoded characters
    decoded_str = quote(encoded_str)
    return decoded_str

def translate_word(word, src_lang="detect", target_lang="en"):
    translator = Translator()
    
    detected_lang = src_lang
    
    if src_lang == "detect":
       detected_lang = translator.detect(word)
       detected_lang = detected_lang.lang
 
    if not detected_lang:
       return ""

    text = translator.translate(word, src=detected_lang, dest=target_lang).text
    return text

def translate_lines(text, src_lang="detect", target_lang="en"):
    lines = text.splitlines()
    
    line = ";".join(lines)
    
    word = translate_word(line, src_lang, target_lang)
    
    word = word.replace(";", "\n")
    
    return word

def send_json_response(server, translated):
    # Prepare response data
    response_data = {
        "data": translated
    }

    # Send HTTP status code
    server.send_response(200)
    server.send_header("Content-Type", "application/json")
    server.end_headers()

    # Send JSON response
    server.wfile.write(json.dumps(response_data).encode("utf-8"))
    
    
def send_text_response(server, translated):
    # Send HTTP status code
    server.send_response(200)
    server.send_header("Content-Type", "application/text")
    server.end_headers()

    # Send Text response
    server.wfile.write(translated.encode("utf-8"))
    
class MyRequestHandler(BaseHTTPRequestHandler):
    def do_GET(self):
        try:
            # Parse URL and query parameters
            parsed_url = urlparse(self.path)
            query_params = parse_qs(parsed_url.query)

            # Example: Access parameter 'name'
            text = query_params.get('text', ['nothing'])[0]  # Default to 'Guest'

            translated = ""
            
            if text in text_decode_cache and text in translate_cache:
               new_text = text_decode_cache[text]
               new_translated = translate_cache[text]
               
               text = new_text
               translated = new_translated
            else:
               new_text = url_decode(text)
               new_translated = translate_lines(new_text)
               
               text_decode_cache[text] = new_text
               translate_cache[text] = new_translated
               
               text = new_text
               translated = new_translated
            
            print(text)
            
            print(translated)

            send_text_response(self, translated)
            
        except Exception as e:
            # Handle unexpected errors
            self.send_response(500)
            self.send_header("Content-Type", "application/json")
            self.end_headers()
            error_message = {"error": str(e)}
            self.wfile.write(json.dumps(error_message).encode("utf-8"))

def run_server(host="localhost", port=5000):
    server_address = (host, port)
    httpd = HTTPServer(server_address, MyRequestHandler)
    print(f"Server running at http://{host}:{port}")
    try:
        httpd.serve_forever()
    except KeyboardInterrupt:
        print("\nShutting down server...")
        httpd.server_close()

